import{_ as l,o as i,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Hapag-Lloyd 赫伯羅特（Hapag-Lloyd AG）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-5_HapagLloyd_赫伯羅特.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-5_HapagLloyd_赫伯羅特.md"}'),r={name:"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-5_HapagLloyd_赫伯羅特.md"};function n(t,a,s,g,p,d){return i(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="hapag-lloyd-赫伯羅特-hapag-lloyd-ag" tabindex="-1">Hapag-Lloyd 赫伯羅特（Hapag-Lloyd AG） <a class="header-anchor" href="#hapag-lloyd-赫伯羅特-hapag-lloyd-ag" aria-label="Permalink to &quot;Hapag-Lloyd 赫伯羅特（Hapag-Lloyd AG）&quot;">​</a></h1><h2 id="基本資訊" tabindex="-1">基本資訊 <a class="header-anchor" href="#基本資訊" aria-label="Permalink to &quot;基本資訊&quot;">​</a></h2><ul><li><strong>全球排名</strong>：第5名（THE Alliance/Premier Alliance核心成員）</li><li><strong>總部</strong>：德國漢堡（Hamburg, Germany）</li><li><strong>船隊規模</strong>：截至2026年3月31日，302艘貨櫃船，總運力約250萬TEU</li><li><strong>實際承載</strong>：擁有或租賃約360萬TEU的貨櫃存量用於貨物運輸</li><li><strong>服務網絡</strong>：全球120多條航線，每年運送數百萬個貨櫃</li></ul><h2 id="重大聯盟變革-從the-alliance到gemini-cooperation" tabindex="-1">重大聯盟變革：從THE Alliance到Gemini Cooperation <a class="header-anchor" href="#重大聯盟變革-從the-alliance到gemini-cooperation" aria-label="Permalink to &quot;重大聯盟變革：從THE Alliance到Gemini Cooperation&quot;">​</a></h2><p>2025年是Hapag-Lloyd歷史上最重要的聯盟轉型年：</p><ul><li><strong>THE Alliance時期</strong>（至2025年1月）：與長榮、HMM、ONE組成THE Alliance</li><li><strong>Gemini Cooperation</strong>（2025年2月起）：退出THE Alliance後，與Maersk成立長期運營合作夥伴關係 <ul><li>約290艘船舶池，總運力340萬TEU（Maersk佔60%，Hapag-Lloyd佔40%）</li><li>涵蓋34條主要航線和29條穿梭航線，採用樞紐輻射模式，12個核心樞紐</li><li><strong>目標</strong>：關鍵航線準點率超過90%（顯著高於行業歷史平均水平）</li><li><strong>市場佔有率</strong>：2025年約21.5%-22%的全球貨櫃運力市場份額</li></ul></li></ul><h2 id="船隊現代化與綠色轉型" tabindex="-1">船隊現代化與綠色轉型 <a class="header-anchor" href="#船隊現代化與綠色轉型" aria-label="Permalink to &quot;船隊現代化與綠色轉型&quot;">​</a></h2><ul><li><strong>甲醇雙燃料訂單</strong>：2025年12月訂購8艘4,500 TEU甲醇雙燃料船舶（2028-2029年交船）</li><li><strong>現有船舶改造</strong>：委託Seaspan公司將5艘10,100 TEU船舶改裝為甲醇雙燃料（2026-2027年）</li><li><strong>長期租約</strong>：計劃租賃14艘新造船（1,800/3,500/4,500 TEU級別），2027-2029年加入船隊</li><li><strong>總體投資</strong>：確認投資最多22艘小於5,000 TEU級別的新貨櫃船</li><li><strong>減碳目標</strong>：2030年前絕對溫室氣體排放減少約三分之一（以2022年為基準），2045年实现船隊淨零排放</li></ul><h2 id="股權結構" tabindex="-1">股權結構 <a class="header-anchor" href="#股權結構" aria-label="Permalink to &quot;股權結構&quot;">​</a></h2><ul><li>CSAV（哥倫比亞）：30.0%</li><li>Klaus Michael Kühne（基希內家族）：30.0%</li><li>HGV漢堡資產管理公司：13.9%</li><li>卡塔爾投資局：12.3%</li><li>沙特公共投資基金（PIF）：10.2%</li><li>自由流通股：3.6%</li></ul><h2 id="_2026年展望" tabindex="-1">2026年展望 <a class="header-anchor" href="#_2026年展望" aria-label="Permalink to &quot;2026年展望&quot;">​</a></h2><p>Gemini Cooperation運行第一年表現穩健，Hapag-Lloyd持續投資小型船舶以補充大型船隊。公司預計2026年市場將保持高複雜性和不確定性。</p><hr><p><strong>資料來源</strong>：Hamburg.com (2026)、Wikipedia、Hapag-Lloyd官方數據（2026-03）、Shipping Telegraph (2025-12)、Supply Chain Brain (2025-12)、Maersk官方新聞稿</p>',14)])])}const c=l(r,[["render",n]]);export{_ as __pageData,c as default};
